{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class IndentationRuleIsExpressionPrefixExpressionTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a multiline IS_EXPRESSION then indent the right hand side`() {
        val code =
            """
            fun foo(any: Any) =
                any is
                    Foo
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a multiline PREFIX_EXPRESSION then indent the operand`() {
        val code =
            """
            fun foo(any: Int) =
                ++
                    42
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a multiline PREFIX_EXPRESSION inside a function body`() {
        val code =
            """
            fun foo(any: Int) {
                val a =
                    ++
                        42
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
","file_path":"ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleIsExpressionPrefixExpressionTest.kt"}

